CREATE TABLE IF NOT EXISTS tb_employment_statuses (employment_status_id INT AUTO_INCREMENT PRIMARY KEY,status_name VARCHAR(120) NOT NULL UNIQUE,sort_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT NULL,KEY idx_reference_active(is_active,sort_order)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS tb_religions (religion_id INT AUTO_INCREMENT PRIMARY KEY,religion_name VARCHAR(120) NOT NULL UNIQUE,sort_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT NULL,KEY idx_reference_active(is_active,sort_order)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS tb_tribes (tribe_id INT AUTO_INCREMENT PRIMARY KEY,tribe_name VARCHAR(120) NOT NULL UNIQUE,sort_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT NULL,KEY idx_reference_active(is_active,sort_order)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS tb_polregions (political_region_id INT AUTO_INCREMENT PRIMARY KEY,region_name VARCHAR(100) NOT NULL UNIQUE,sort_order INT NOT NULL DEFAULT 0,is_active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME DEFAULT NULL,KEY idx_political_region_active(is_active,sort_order)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE tb_pension_beneficiaries ADD COLUMN IF NOT EXISTS gender VARCHAR(20) DEFAULT NULL,ADD COLUMN IF NOT EXISTS bank_name VARCHAR(120) DEFAULT NULL,ADD COLUMN IF NOT EXISTS bank_account VARCHAR(80) DEFAULT NULL,ADD COLUMN IF NOT EXISTS bank_branch VARCHAR(120) DEFAULT NULL,ADD COLUMN IF NOT EXISTS earning_basis_date DATE DEFAULT NULL,ADD COLUMN IF NOT EXISTS earning_expiry_date DATE DEFAULT NULL,ADD COLUMN IF NOT EXISTS last_earning_month DATE DEFAULT NULL,ADD COLUMN IF NOT EXISTS earning_period_label VARCHAR(100) DEFAULT NULL;
ALTER TABLE tb_staffdue ADD COLUMN IF NOT EXISTS dateOfDeath DATE DEFAULT NULL;
